import React from "react";

export default function CallPopup({ callerId, callType, onAccept, onReject }) {
  return (
    <div style={styles.overlay}>
      <div style={styles.popup}>
        <h3>{callerId} is calling ({callType})</h3>
        <button style={styles.acceptBtn} onClick={onAccept}>Accept</button>
        <button style={styles.rejectBtn} onClick={onReject}>Reject</button>
      </div>
    </div>
  );
}

const styles = {
  overlay: {
    position: "fixed", top: 0, left: 0, right: 0, bottom: 0,
    backgroundColor: "rgba(0,0,0,0.5)", display: "flex",
    justifyContent: "center", alignItems: "center"
  },
  popup: {
    backgroundColor: "white", padding: 20, borderRadius: 10, textAlign: "center"
  },
  acceptBtn: { margin: 10, padding: "10px 20px", backgroundColor: "#25D366", color: "white", border: "none", borderRadius: 5 },
  rejectBtn: { margin: 10, padding: "10px 20px", backgroundColor: "#d9534f", color: "white", border: "none", borderRadius: 5 }
};
